  VALUES (19, 50, 'quiz', $json${"questions":[{"q":"«Me entreno»:","options":["je m'entraîne","je entraîne","j'entraîne me"],"correct":0},{"q":"«Quisiera inscribirme»:","options":["Je voudrais m'inscrire.","Je voudrais inscrire.","Je voudrais me inscrire."],"correct":0},{"q":"«Un abono mensual»:","options":["un abonnement mensuel","un abonnement annuel","une séance"],"correct":0},{"q":"«Descansar»:","options":["se reposer","se muscler","s'entraîner"],"correct":0},{"q":"«¿Está incluido en el abono?»:","options":["C'est inclus dans l'abonnement ?","C'est inclus dans l'abonné ?","Est inclus l'abonnement ?"],"correct":0}]}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
