INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (20, 20, 'text', $json${"title":"📖 Révision intégrée — J'OSE","body":"Hoy repasas TODO el mes J'OSE. Recuerda las herramientas clave:\n• Je voudrais… (cortesía) · sans/avec · cantidades.\n• Il y a / il n'y a pas de · pour + infinitif · avoir mal à.\n• Comparatifs (plus/moins/aussi… que) · démonstratifs (ce/cette/ces).\n• Partitifs (du/de la/des) · verbes pronominaux (je me…).\n\nÚsalas todas juntas en situaciones reales: café, panadería, restaurante, supermercado, transporte, direcciones, farmacia, tienda, mercado y gimnasio."}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (20, 30, 'vocab', $json${"items":[{"fr":"se tonifier","es":"tonificarse"},{"fr":"perdre du poids","es":"perder peso"},{"fr":"prendre du muscle","es":"ganar músculo"},{"fr":"transpirer","es":"sudar"},{"fr":"se reposer","es":"descansar"},{"fr":"récupérer","es":"recuperarse"},{"fr":"progresser","es":"progresar"},{"fr":"s'améliorer","es":"mejorar"},{"fr":"se blesser","es":"lesionarse"},{"fr":"se dépasser","es":"superarse"},{"fr":"être en forme","es":"estar en forma"},{"fr":"tenir la forme","es":"mantenerse en forma"},{"fr":"se sentir bien","es":"sentirse bien"},{"fr":"être fatigué(e)","es":"estar cansado/a"},{"fr":"avoir des courbatures","es":"tener agujetas"},{"fr":"un objectif","es":"un objetivo"},{"fr":"un résultat","es":"un resultado"},{"fr":"la motivation","es":"la motivación"},{"fr":"un suivi","es":"un seguimiento"},{"fr":"un programme personnalisé","es":"un programa personalizado"},{"fr":"peser","es":"pesar"},{"fr":"souffler","es":"tomar aliento"},{"fr":"Je m'entraîne trois fois par semaine.","es":"Me entreno tres veces a la semana."},{"fr":"Je voudrais m'inscrire.","es":"Quisiera inscribirme."},{"fr":"C'est inclus dans l'abonnement ?","es":"¿Está incluido en el abono?"},{"fr":"Je veux me remettre en forme.","es":"Quiero ponerme en forma."},{"fr":"Quel est votre objectif ?","es":"¿Cuál es su objetivo?"},{"fr":"avoir la patate","es":"tener energía (informal)"},{"fr":"un bilan","es":"una evaluación"},{"fr":"Je fais du sport pour me sentir bien.","es":"Hago deporte para sentirme bien."}]}$json$::jsonb);
