INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (20, 60, 'text', $json${"title":"🏆 Défi final du mois — J'ose vivre en français","body":"¡Felicidades! Llegas al reto final del Mes 1: J'OSE.\n\nGraba un audio o video de 3 a 5 minutos resolviendo 5 mini situaciones reales que mezclen los contextos del mes (por ejemplo: pedir en un café, comprar en el mercado, pedir indicaciones, describir un síntoma en la farmacia, inscribirte en el gimnasio).\n\nUsa las estructuras del mes: je voudrais, il y a, pour aller à, avoir mal à, comparatifs, partitifs, verbes pronominaux.\n\n🏅 Medalla: « Parisien(ne) accompli(e) » — Sais acheter, comparer et décider en français. Félicitations !\n\n💬 « La fluidez nace usando el idioma antes de sentirte listo/a. J'OSE ! »"}$json$::jsonb);
INSERT INTO public.authored_blocks (day_id, sort, type, payload)
  VALUES (20, 70, 'speaking', $json${"title":"🎙️ Reto final J'OSE — 5 situaciones reales","prompt":"Graba tu audio/video de 3-5 minutos resolviendo 5 situaciones reales del mes en francés (café, mercado, direcciones, farmacia, gimnasio). Aquí puedes practicar y grabar tu intento.","example":"Bonjour ! Je voudrais un café, s'il vous plaît. … Pour aller au marché, s'il vous plaît ? … Un kilo de pommes et une barquette de fraises. … J'ai mal à la tête depuis hier, qu'est-ce que vous me conseillez ? … Je voudrais m'inscrire à la salle de sport."}$json$::jsonb);

